from flask import Flask, request, jsonify, session
from werkzeug.security import generate_password_hash, check_password_hash

app = Flask(__name__)
app.secret_key = "replace-with-a-secure-secret-key"


def get_current_user():
    user = session.get("user")
    return user if user else None


def update_user_profile(user, data):
    updated = {}

    if "email" in data:
        email = str(data["email"]).strip().lower()
        if not email or "@" not in email:
            return None, {"error": "Invalid email"}, 400
        user["email"] = email
        updated["email"] = email

    if "password" in data:
        password = str(data["password"])
        if len(password) < 8:
            return None, {"error": "Password must be at least 8 characters"}, 400
        user["password_hash"] = generate_password_hash(password)
        updated["password"] = "updated"

    if "two_factor_enabled" in data:
        two_factor_enabled = data["two_factor_enabled"]
        if not isinstance(two_factor_enabled, bool):
            return None, {"error": "two_factor_enabled must be a boolean"}, 400
        user["two_factor_enabled"] = two_factor_enabled
        updated["two_factor_enabled"] = two_factor_enabled

    if "two_factor_method" in data:
        method = str(data["two_factor_method"]).strip().lower()
        if method not in {"app", "sms", "email"}:
            return None, {"error": "Invalid two_factor_method"}, 400
        user["two_factor_method"] = method
        updated["two_factor_method"] = method

    return updated, None, None


@app.route("/api/profile", methods=["POST"])
def update_profile():
    user = get_current_user()
    if not user:
        return jsonify({"error": "Unauthorized"}), 401

    data = request.get_json(silent=True)
    if not isinstance(data, dict):
        return jsonify({"error": "Invalid JSON body"}), 400

    allowed_fields = {"email", "password", "two_factor_enabled", "two_factor_method"}
    if not any(field in data for field in allowed_fields):
        return jsonify({"error": "No updatable fields provided"}), 400

    updated, error_body, status_code = update_user_profile(user, data)
    if error_body:
        return jsonify(error_body), status_code

    session["user"] = user

    return jsonify({
        "message": "Profile updated successfully",
        "updated": updated
    }), 200


if __name__ == "__main__":
    app.run(debug=True)